queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?network_admin a :Network_Admin .
    ?network_admin p:Position ?position .
    ?network_admin p:Salary ?salary_f .
    FILTER(STR(?salary_f) = "$70,000")
    BIND(?position AS ?o0)
  }
  UNION
  {
    ?it_consultant a :IT_Consultant .
    ?it_consultant p:Type ?type .
    ?it_consultant p:Salary ?salary_f .
    FILTER(STR(?salary_f) = "$70,000")
    BIND(?type AS ?o0)
  }
}

